93	def CudaTile_OptimizationHintsAttr : CudaTileAttrDef<"OptimizationHints", "optimization_hints", "13.1"> {
94	  let parameters = (ins "DictionaryAttr":$value);
95	  let description = [{
96	    The :code:`optimization_hints` attribute provides architecture-specific compiler hints in the form of nested dictionaries.
97	
98	    The hints are specified for each architecture (e.g., :code:`sm_100`, :code:`sm_120`) and for each architecture the user can specify
99	    specific hints for each operation.
100	
101	    - :code:`num_cta_in_cga` - suggest the number of CTAs in a CGA (which must be the power of 2 less than or equal to 16) for :ref:`op-cuda_tile.entry`.
102	    - :code:`num_worker_warps_per_cta` - suggest the number of worker warps per CTA (which only support [4, 8] currently) for :ref:`op-cuda_tile.entry`.
103	    - :code:`allow_tma` - suggest whether to use TMA for :ref:`op-cuda_tile.load_view_tko` and :ref:`op-cuda_tile.store_view_tko`.
104	    - :code:`latency` - latency hint for :ref:`op-cuda_tile.load_view_tko` and :ref:`op-cuda_tile.store_view_tko`.
105	
106	    User can specify :code:`default` hint that will be used when no target-specific hint is provided
107	    (and only when :code:`default` hint value is in the valid range for the current compilation target).
108	
109	    For example they can be annotated as:
110	
111	    .. code-block:: mlir
112	
113	      optimization_hints=<
114	        sm_100 = {num_cta_in_cga = 8, num_worker_warps_per_cta = 8},
115	        sm_120 = {num_cta_in_cga = 16, num_worker_warps_per_cta = 4}
116	      >
117	  }];
118	
119	  let descriptionTables = [
120	    Table<":code: Optimization Hints", "The below table shows the supported optimization hints for each operation type.",
121	      [TableHeader<"Optimization Hint", "code">, TableHeader<"EntryOp">,
122	       TableHeader<"LoadViewTkoOp, StoreViewTkoOp">,
123	       TableHeader<"LoadPtrTkoOp, StorePtrTkoOp">],
124	      [       TableRow<["num_cta_in_cga", "yes", "no", "no"]>,
125	       TableRow<["num_worker_warps_per_cta", "yes", "no", "no"]>,
126	       TableRow<["allow_tma", "no", "yes", "no"]>,
127	       TableRow<["latency", "no", "yes", "yes"]>]
128	    >
129	  ];
130	  let hasCustomAssemblyFormat = 1;
131	  let cppNamespace = "::mlir::cuda_tile";
132	  let genVerifyDecl = 1;
133	
134	  let extraClassDeclaration = [{
135	
136	  private:
137	    static constexpr llvm::StringLiteral kDefault = "default";
138	    static constexpr llvm::StringLiteral knownKeysArr[] = {
139	        "sm_80",
140	        "sm_86",
141	        "sm_87", 
142	        "sm_88", 
143	        "sm_89", 
144	        "sm_90", 
145	        "sm_100", 
146	        "sm_103",
147	        "sm_110", 
148	        "sm_120", 
149	        "sm_121", 
150	        kDefault};
151	    
152	    static bool isKnownKey(llvm::StringRef key) {
153	      return llvm::is_contained(knownKeysArr, key);
154	    }
155	
156	    mlir::LogicalResult verifyParamWithContext(Location loc,
157	                                               llvm::StringRef context,
158	                                               ArrayRef<StringRef> keysValidForOperation,
159	                                               DictionaryAttr &attr);
160	    std::optional<Attribute> getAttributeForSmOrDefault(DictionaryAttr value, StringRef sm, StringRef key);
161	  public:
162	    static constexpr llvm::StringLiteral kNumCTAInCGA = "num_cta_in_cga";
163	    static constexpr llvm::StringLiteral kNumWorkerWarpsPerCTA = "num_worker_warps_per_cta";
164	    static constexpr llvm::StringLiteral kAllowTMA = "allow_tma";
165	    static constexpr llvm::StringLiteral kLatency = "latency";
166	    static constexpr llvm::StringLiteral kOccupancy = "occupancy";
167	    static constexpr llvm::StringLiteral allowedKeysArr[] = {
168	        "sm_80", "sm_86", "sm_87", "sm_88", "sm_89", "sm_90", "sm_100", "sm_103", "sm_110", "sm_120", "sm_121"};
169	
170	    static bool isAllowedKey(llvm::StringRef key) {
171	      return llvm::is_contained(allowedKeysArr, key);
172	    }
173	
174	    static mlir::LogicalResult verifyParamWithContext(llvm::function_ref<InFlightDiagnostic()> emitError,
175	                                               llvm::StringRef context,
176	                                               ArrayRef<StringRef> allowedKeys,
177	                                               DictionaryAttr &attr);
178	  public:
179	    std::optional<int> getNumCTAInCGA(StringRef sm);
180	    std::optional<int> getNumWorkerWarpsPerCTA(StringRef sm);
181	    std::optional<bool> getAllowTMA(StringRef sm);
182	    std::optional<int> getLatency(StringRef sm);
183	    std::optional<int> getOccupancy(StringRef sm);
184	    mlir::LogicalResult verifyWithOp(Operation *op, DictionaryAttr value);
185	
186	  }];
