439	def CudaTile_BoundedAttr : CudaTileAttrDef<
440	    "Bounded", "bounded", "13.1",
441	    [DeclareAttrInterfaceMethods<CudaTile_AssumePredicateAttrInterface>]> {
442	  let description = [{
443	    .. code-block:: mlir
444	
445	      #bounded<(lb|?), (ub|?)>
446	
447	    The :code:`bounded` attribute must be used as a predicate for
448	    :code:`cuda_tile.assume`. The predicated value must be a tile of integers.
449	
450	    :code:`bounded` specifies a lower and upper bound for all elements of the
451	    predicated tile when interpreted as signed integers. Bounds are optional:
452	    it is possible to leave a bound unspecified, as indicated by "?" in the
