270	    CudaTileArg<UnitAttr, alloca_is_global_address, "13.3">:$global
271	  );
272	  let results = (
273	    outs CudaTileArg<CudaTile_ScalarTileOf<CudaTile_PointerType>,
274	                    "The result tile of pointer.", "13.3">:$result
275	  );
